import { useState } from "react";
import { getPatients, getAppointments, getPrescriptions } from "../api";

export default function Search() {
  const [phone, setPhone] = useState("");
  const [loading, setLoading] = useState(false);

  const [patients, setPatients] = useState([]);
  const [appointments, setAppointments] = useState([]);
  const [prescriptions, setPrescriptions] = useState([]);

  const [error, setError] = useState("");

  const handleSearch = async () => {
    setLoading(true);
    setError("");

    try {
      if (!phone) {
        setError("Please enter a phone number");
        setLoading(false);
        return;
      }

      // 1. Get all patients and filter by phone (safe fallback approach)
      const allPatients = await getPatients();

      const matchedPatients = allPatients.filter((p) =>
        p.phone?.toString().includes(phone)
      );

      setPatients(matchedPatients);

      // 2. Get appointments (then filter locally)
      const allAppointments = await getAppointments();

      const matchedAppointments = allAppointments.filter((a) =>
        matchedPatients.some((p) => p.id === a.patient_id)
      );

      setAppointments(matchedAppointments);

      // 3. Get prescriptions (safe flexible call)
      let allPrescriptions = [];

      try {
        allPrescriptions = await getPrescriptions();
      } catch (err) {
        console.log("Prescription API not available or needs params:", err);
      }

      const matchedPrescriptions = allPrescriptions.filter((pr) =>
        matchedPatients.some((p) => p.id === pr.patient_id)
      );

      setPrescriptions(matchedPrescriptions);
    } catch (err) {
      console.error("Search error:", err);
      setError("Failed to fetch data. Check backend connection.");
    }

    setLoading(false);
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Search Patient</h2>

      <input
        type="text"
        placeholder="Enter phone number"
        value={phone}
        onChange={(e) => setPhone(e.target.value)}
        style={{ padding: "8px", marginRight: "10px" }}
      />

      <button onClick={handleSearch} disabled={loading}>
        {loading ? "Searching..." : "Search"}
      </button>

      {error && <p style={{ color: "red" }}>{error}</p>}

      {/* PATIENT DETAILS */}
      <h3>Patients</h3>
      {patients.map((p) => (
        <div key={p.id} style={{ border: "1px solid #ccc", margin: "5px", padding: "10px" }}>
          <p><b>Name:</b> {p.name}</p>
          <p><b>Phone:</b> {p.phone}</p>
          <p><b>Age:</b> {p.age}</p>
        </div>
      ))}

      {/* APPOINTMENTS */}
      <h3>Appointments</h3>
      {appointments.map((a, index) => (
        <div key={index} style={{ border: "1px solid #ddd", margin: "5px", padding: "10px" }}>
          <p><b>Date:</b> {a.date}</p>
          <p><b>Patient ID:</b> {a.patient_id}</p>
        </div>
      ))}

      {/* PRESCRIPTIONS */}
      <h3>Prescriptions</h3>
      {prescriptions.map((pr, index) => (
        <div key={index} style={{ border: "1px solid #ddd", margin: "5px", padding: "10px" }}>
          <p><b>Medicine:</b> {pr.medicine}</p>
          <p><b>Notes:</b> {pr.notes}</p>
          <p><b>Patient ID:</b> {pr.patient_id}</p>
        </div>
      ))}
    </div>
  );
}
